import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { Readable } from "stream";

async function startServer() {
  const app = express();
  const PORT = 3000;

  app.use(express.json());

  // Handle CORS Preflight / OPTIONS
  app.options("/api/proxy-stream", (req, res) => {
    res.setHeader("Access-Control-Allow-Origin", "*");
    res.setHeader("Access-Control-Allow-Methods", "GET, HEAD, OPTIONS");
    res.setHeader("Access-Control-Allow-Headers", "*");
    res.sendStatus(200);
  });

  // Proxy endpoint to play any IPTV streams (including HTTP ones) securely over HTTPS players
  app.get("/api/proxy-stream", async (req, res) => {
    const streamUrl = (req.query.url || req.query.stream) as string;
    if (!streamUrl) {
      return res.status(400).send("url parameter is required");
    }

    // Set CORS headers early
    res.setHeader("Access-Control-Allow-Origin", "*");
    res.setHeader("Access-Control-Allow-Methods", "GET, HEAD, OPTIONS");
    res.setHeader("Access-Control-Allow-Headers", "*");

    try {
      const headersToForward: Record<string, string> = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        'Accept': '*/*'
      };

      // Forward client's Range header if requested
      if (req.headers.range) {
        headersToForward['Range'] = req.headers.range;
      }

      const response = await fetch(streamUrl, {
        headers: headersToForward
      });

      if (!response.ok && response.status !== 206) {
        return res.status(response.status).send(`Failed to fetch media: ${response.statusText}`);
      }

      const contentType = response.headers.get("content-type") || "";
      const isPlaylist = streamUrl.toLowerCase().split('?')[0].endsWith(".m3u8") || 
                         streamUrl.toLowerCase().split('?')[0].endsWith(".m3u") || 
                         contentType.toLowerCase().includes("mpegurl") || 
                         contentType.toLowerCase().includes("mpegURL") || 
                         contentType.toLowerCase().includes("application/x-mpegurl");

      if (isPlaylist) {
        let protocol = (req.headers['x-forwarded-proto'] as string) || req.protocol || "https";
        if (protocol.includes(",")) {
          protocol = protocol.split(",")[0].trim();
        }
        const proxyHost = req.get('host') || "localhost:3000";
        const proxyBase = `${protocol}://${proxyHost}/api/proxy-stream`;

        const text = await response.text();
        let baseUrl = streamUrl;
        try {
          const parsedUrl = new URL(streamUrl);
          baseUrl = parsedUrl.origin + parsedUrl.pathname.substring(0, parsedUrl.pathname.lastIndexOf("/") + 1);
        } catch (e) {
          baseUrl = streamUrl.substring(0, streamUrl.lastIndexOf("/") + 1);
        }

        const lines = text.split("\n");
        const rewrittenLines = lines.map(line => {
          const trimmed = line.trim();
          if (!trimmed) return line;

          if (trimmed.startsWith("#")) {
            // Rewrite URI references in attributes such as #EXT-X-KEY:METHOD=AES-128,URI="http://..."
            if (trimmed.includes('URI=')) {
              return trimmed.replace(/URI="([^"]+)"/g, (match, p1) => {
                let absoluteUri = p1;
                if (!p1.startsWith("http://") && !p1.startsWith("https://")) {
                  try {
                    absoluteUri = new URL(p1, streamUrl).href;
                  } catch (e) {
                    absoluteUri = baseUrl + p1;
                  }
                }
                return `URI="${proxyBase}?url=${encodeURIComponent(absoluteUri)}"`;
              });
            }
            return line;
          }

          // Resolve absolute URL for relative stream chunks
          let absoluteUrl = trimmed;
          if (!trimmed.startsWith("http://") && !trimmed.startsWith("https://")) {
            try {
              absoluteUrl = new URL(trimmed, streamUrl).href;
            } catch (e) {
              absoluteUrl = baseUrl + trimmed;
            }
          }

          return `${proxyBase}?url=${encodeURIComponent(absoluteUrl)}`;
        });

        res.setHeader("Content-Type", "application/vnd.apple.mpegurl");
        res.setHeader("Cache-Control", "no-cache");
        return res.send(rewrittenLines.join("\n"));
      } else {
        // Dynamic segment data (.ts, audio file, video chunk, etc.)
        res.status(response.status);

        // Forward important headers of stream chunk back
        const copyHeaders = ['content-type', 'content-length', 'content-range', 'accept-ranges', 'cache-control'];
        copyHeaders.forEach(h => {
          const val = response.headers.get(h);
          if (val) {
            res.setHeader(h, val);
          }
        });

        if (!res.getHeader('content-type')) {
          res.setHeader("Content-Type", contentType || "video/mp2t");
        }

        if (response.body) {
          // Stream the chunk data back to the client natively using Node streams
          try {
            const readable = Readable.fromWeb(response.body as any);
            readable.pipe(res);
          } catch (streamError) {
            console.error("Readable.fromWeb error, falling back:", streamError);
            const buffer = await response.arrayBuffer();
            res.send(Buffer.from(buffer));
          }
        } else {
          const buffer = await response.arrayBuffer();
          res.send(Buffer.from(buffer));
        }
      }
    } catch (err: any) {
      console.error("Stream Proxy Error for url:", streamUrl, err);
      res.status(500).send("Proxy error: " + err.message);
    }
  });

  // Vite middleware for development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();
